add-two-numbers.py<pre><code># Definition for singly-linked list.
# class ListNode:
#     def __init__(self, val=0, next=None):
#         self.val = val
#         self.next = next
class Solution:
def addTwoNumbers(self, l1: Optional[ListNode], l2: Optional[ListNode]) -&gt; Optional[ListNode]:
curr = res = ListNode(-1)
carry = 0
while l1 or l2 or carry:
if l1:
carry += l1.val
l1 = l1.next
if l2:
carry += l2.val
l2 = l2.next
curr.next = ListNode(carry % 10)
curr = curr.next
carry //= 10
return res.next
</code></pre> add-two-numbers.cpp<pre><code>/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
ListNode* addTwoNumbers(ListNode* l1, ListNode* l2) {
ListNode res(-1), *curr = &amp;res;
int carry = 0;
while (l1 || l2 || carry &gt; 0){
if (l1){
carry += l1-&gt;val;
l1 = l1-&gt;next;
}
if (l2){
carry += l2-&gt;val;
l2 = l2-&gt;next;
}
curr-&gt;next = new ListNode(carry%10);
curr = curr-&gt;next;
carry /= 10;
}
return res.next;
}
};
</code></pre>

median-of-two-sorted-arrays.py<pre><code>class Solution:
def findMedianSortedArrays(self, A: List[int], B: List[int]) -&gt; float:
m, n = len(A), len(B)
if m &gt; n: return self.findMedianSortedArrays(B, A)
half = (m + n + 1) // 2
left, right = 0, m
while left &lt;= right:
i = (left + right) // 2
j = half - i
if i &lt; m and j - 1 &gt;= 0 and B[j - 1] &gt; A[i]:
left = i + 1
elif i - 1 &gt;= 0 and j &lt; n and A[i - 1] &gt; B[j]:
right = i - 1
else:
if i == 0:
left_max = B[j - 1]
elif j == 0:
left_max = A[i - 1]
else:
left_max = max(A[i - 1], B[j - 1])
if (m + n) &amp; 1:
return left_max
if i == m:
right_min = B[j]
elif j == n:
right_min = A[i]
else:
right_min = min(A[i], B[j])
return (left_max + right_min) / 2
</code></pre>

string-to-integer-atoi.py<pre><code>class Solution:
def myAtoi(self, s: str) -&gt; int:
INT_MIN = -2 ** 31
INT_MAX = 2 ** 31 - 1
n = len(s)
res = i = 0
while i &lt; n and s[i] == " ":
i += 1
if i == n: return 0
is_negative = False
if s[i] == "-":
is_negative = True
if s[i] in '+-':
i += 1
while i &lt; n and s[i].isdecimal():
res = res * 10 + int(s[i])
i += 1
if is_negative:
res *= -1
return max(INT_MIN, min(res, INT_MAX))
</code></pre>

container-with-most-water.py<pre><code>class Solution:
def maxArea(self, height: List[int]) -&gt; int:
n = len(height)
res = 0
left, right = 0, n - 1
while left &lt; right:
res = max(res, (right - left) * min(height[left], height[right]))
if height[left] &lt; height[right]:
left += 1
else:
right -= 1
return res
