</code></pre> merge-two-sorted-lists.cpp<pre><code>/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
ListNode* mergeTwoLists(ListNode* l1, ListNode* l2) {
ListNode *curr = new ListNode;
curr-&gt;val = -1;
curr-&gt;next = NULL;
ListNode *res = curr;
while (l1 != nullptr &amp;&amp; l2 != nullptr){
if (l1-&gt;val &lt; l2-&gt;val){
curr-&gt;next = l1;
l1 = l1-&gt;next;
}else{
curr-&gt;next = l2;
l2 = l2-&gt;next;
}
curr = curr-&gt;next;
}
ListNode *leftover = (l1 == nullptr) ? l2 : l1;
curr-&gt;next = leftover;
return res-&gt;next;
}
};
</code></pre>

generate-parentheses.py<pre><code>class Solution:
def generateParenthesis(self, n: int) -&gt; List[str]:
res = []
def backtrack(opened, closed, curr):
if opened == closed == n:
res.append(curr)
return
if closed &lt; opened:
backtrack(opened, closed + 1, curr + ")")
if opened &lt; n:
backtrack(opened + 1, closed, curr + "(")
backtrack(0, 0, "")
return res
</code></pre>

merge-k-sorted-lists.py<pre><code># Definition for singly-linked list.
# class ListNode:
#     def __init__(self, val=0, next=None):
#         self.val = val
#         self.next = next
class Solution:
def mergeKLists(self, lists: List[Optional[ListNode]]) -&gt; Optional[ListNode]:
if not lists: return None
n = len(lists)
def mergeLists(start, end):
if start == end: 
return lists[start]
elif start &lt; end:
mid = start + (end - start) // 2
l1 = mergeLists(start, mid)
l2 = mergeLists(mid + 1, end)
return merge(l1, l2)
else:
return None
def merge(l1, l2):
if not l1: return l2
if not l2: return l1
res = curr = ListNode()
while l1 and l2:
if l1.val &lt;= l2.val:
curr.next = ListNode(l1.val)
l1 = l1.next
else:
curr.next = ListNode(l2.val)
l2 = l2.next
curr = curr.next
curr.next = l1 or l2
return res.next
return mergeLists(0, n - 1)
</code></pre>

