def backtrack(i, path, curr, prev):
if i == n:
if curr == target:
res.append(path)
return
for j in range(i, n):
if j &gt; i and s[i] == '0': break
num = int(s[i : j + 1])
if i == 0:
backtrack(j + 1, path + str(num), curr + num, num)
