class Solution:
def rob(self, root: Optional[TreeNode]) -&gt; int:
@cache
def rob(node):
if not node: return 0
rob_this = node.val + not_rob(node.left) + not_rob(node.right)
not_rob_this = not_rob(node)
return max(rob_this, not_rob_this)
