def move(h1, h2):
value, index = heapq.heappop(h1)
heapq.heappush(h2, (-value, index))
def median():
return float(large[0][0]) if k &amp; 1 else (large[0][0] - small[0][0]) / 2
small, large = [], []
for i in range(k):
heapq.heappush(small, (-nums[i], i))
for _ in range(k - (k &gt;&gt; 1)):
move(small, large)
