if x &gt;= large[0][0]:
heapq.heappush(large, (x, i + k))
if nums[i] &lt;= large[0][0]:
move(large, small)
else:
heapq.heappush(small, (-x, i + k))
if nums[i] &gt;= large[0][0]:
move(small, large)
while small and small[0][1] &lt;= i:
heapq.heappop(small)
while large and large[0][1] &lt;= i:
heapq.heappop(large)
res.append(median())
return res
