def __init__(self, n):
self.graph = list(range(n))
def find(self, x):
if self.graph[x] != x:
self.graph[x] = self.find(self.graph[x])
return self.graph[x]
def union(self, x, y):
ux, uy = self.find(x), self.find(y)
self.graph[ux] = uy
def connected(self, x, y):
return self.find(x) == self.find(y)
class Solution:
def findCircleNum(self, G: List[List[int]]) -&gt; int:
n = len(G)
