if len(recList) &lt;= i:
recList.append(curr)
return
r = recList[i]
if curr[2] &lt;= r[0] or curr[3] &lt;= r[1] or curr[0] &gt;= r[2] or curr[1] &gt;= r[3]:
mergeRec(recList, curr, i + 1)
