int m = n * n;
vector&lt;bool&gt; visited(m + 1, false);
visited[1] = true;
deque&lt;int&gt; queue = {1};
int moves = 1;
while (!queue.empty()) {
for (int i = 0, l = (int)queue.size(); i &lt; l; i++) {
int u = queue.front();
queue.pop_front();
for (int v = u + 1, k = min(m, u + 6); v &lt;= k; v++) {
int y = n - 1 - (v - 1) / n;
int x = (v - 1) % n;
if ((v - 1) / n % 2) x = n - 1 - x;
int w = board[y][x] == -1 ? v : board[y][x];
if (w == m) return moves;
if (!visited[w]) {
visited[w] = true;
queue.push_back(w);
}
}
}
moves++;
}
return -1;
}
};
