find-the-shortest-superstring.py<pre><code>class Solution:
def shortestSuperstring(self, words: List[str]) -&gt; str:
def distance(s1, s2):
for i in range(1, len(s1)):
if s2.startswith(s1[i:]):
return len(s1) - i + 1
return 1
n = len(words)
weights = [[0] * n for _ in range(n)]
dp = [[0] * n for _ in range(1 &lt;&lt; n)]
queue = deque([(0, i, 1 &lt;&lt; i, [i]) for i in range(n)])
full_mask = (1 &lt;&lt; n) - 1
maxWeight, maxPath = -1, []
for i in range(n):
for j in range(i, n):
weights[i][j] = distance(words[i], words[j])
weights[j][i] = distance(words[j], words[i])
while queue:
w, node, mask, path = queue.popleft()
if dp[mask][node] != w:
continue
if mask == full_mask and w &gt; maxWeight:
maxWeight = w
maxPath = path
continue
for nei in range(n):
if mask &amp; (1 &lt;&lt; nei) &gt; 0: continue
new_mask = mask | (1 &lt;&lt; nei)
old = dp[new_mask][nei]
new = dp[mask][node] + weights[node][nei]
if new &gt; old:
dp[new_mask][nei] = new
queue.append((new, nei, new_mask, path + [nei]))
res = words[maxPath[0]]
for i in range(1, n):
prev, curr = maxPath[i - 1], maxPath[i]
overlap = weights[prev][curr] - 1
res += words[curr][overlap:]
return res
</code></pre>

