for x, i in sorted((x, i) for i, x in enumerate(arr)):
while stack and stack[-1] &lt; i:
next_higher[stack.pop()] = i
stack.append(i)
stack = []
for x, i in sorted((-x, i) for i, x in enumerate(arr)):
while stack and stack[-1] &lt; i:
next_lower[stack.pop()] = i
stack.append(i)
odd, even = [0] * n, [0] * n
odd[-1] = even[-1] = 1
for i in range(n - 2, -1, -1):
