satisfiability-of-equality-equations.py<pre><code>class UnionFind:
def __init__(self):
self._parent = {}
self._size = {}
def union(self, a, b):
a, b = self.find(a), self.find(b)
if a == b:
return
if self._size[a] &lt; self._size[b]:
a, b = b, a
self._parent[b] = a
self._size[a] += self._size[b]
def find(self, x):
if x not in self._parent:
self._parent[x] = x
self._size[x] = 1
while self._parent[x] != x:
self._parent[x] = self._parent[self._parent[x]]
x = self._parent[x]
return x
class Solution:
def equationsPossible(self, equations: List[str]) -&gt; bool:
N = len(equations)
uf = UnionFind()
for x, e, _ , y in equations:
if e == "=":
uf.union(x, y)
return not any(e == "!" and uf.find(x) == uf.find(y) for x, e, _, y in equations)
</code></pre>

