while stack and stack[-1] != "(":
seen.add(stack.pop())
stack.pop()
operator = stack.pop()
stack.append(all(seen) if operator == "&amp;" else any(seen) if operator == "|" else not seen.pop())
elif c != ",":
stack.append(True if c == 't' else False if c == 'f' else c)
return stack.pop()
