if(nums[i] == 0){
sum = 0;
firstNegative = -1;
zeroPosition = i;
}
else{
// consider index of zero
if(sum%2 == 0) max = Math.max(i - zeroPosition, max);
// consider index of first negative number
else max = Math.max(i - firstNegative, max);   }
}
return max;
}
}
