curr-&gt;next = list1;
ListNode *res = curr;
for (int i = 0; i &lt; a; i++)
curr = curr-&gt;next;
ListNode *prev = curr;
for (int i = 0; i &lt; b-a+1; i++)
curr = curr-&gt;next;
ListNode *temp = list2;
while (temp-&gt;next)
temp = temp-&gt;next;
temp-&gt;next = curr-&gt;next;
prev-&gt;next = list2;
return res-&gt;next;
}
};
