number-of-restricted-paths-from-first-to-last-node.py<pre><code>class Solution:
def countRestrictedPaths(self, n: int, edges: List[List[int]]) -&gt; int:
M = 10 ** 9 + 7
graph = collections.defaultdict(list)
dist = [float('inf')] * n
dist[n - 1] = 0
for u, v, w in edges:
u -= 1
v -= 1
graph[u].append((w, v))
graph[v].append((w, u))
pq = [(0, n - 1)]
while pq:
d, src = heapq.heappop(pq)
if dist[src] != d: continue
for weight, nei in graph[src]:
old = dist[nei]
new = dist[src] + weight
if new &lt; old:
dist[nei] = new
heapq.heappush(pq, (new, nei))
@cache
def dfs(x):
if x == n - 1: return 1
res = 0
for _, nei in graph[x]:
if dist[x] &gt; dist[nei]:
res = (res + dfs(nei)) % M
return res
return dfs(0)
</code></pre>

