preferred, ind = Q[p2][1], Q[p2][2]
i = aval.bisect(preferred)
cands = []
if i &gt; 0: cands.append(aval[i-1])
if i &lt; len(aval): cands.append(aval[i])
ans[ind] = min(cands, key = lambda x: abs(x - preferred))
p2 += 1
return ans
