mask1, len1 = A[i]
if len1 ** 2 &lt; res: break
for j in range(i + 1, len(A)):
mask2, len2 = A[j]
if mask1 &amp; mask2 == 0 and len1 * len2 &gt; res:
res = len1 * len2
break
return res
