partition-array-into-two-arrays-to-minimize-sum-difference.py<pre><code>class Solution:
def minimumDifference(self, nums: List[int]) -&gt; int:
def construct(A):
n = len(A)
mp = {}
for k in range(1, n + 1):
sums = []
for comb in combinations(A, k):
sums.append(sum(comb))
mp[k] = sums
return mp
n = len(nums) // 2
left, right = nums[:n], nums[n:]
left_part, right_part = construct(left), construct(right)
res = abs(sum(left) - sum(right))
total = sum(nums)
half = total // 2
for k in range(1, n - 1):
l, r = left_part[k], right_part[n - k]
r.sort()
for x in l:
target = half - x
index = bisect.bisect_left(r, target)
for p in (index - 1, index):
if 0 &lt;= p &lt; len(r):
leftSum = x + r[p]
rightSum = total - leftSum
res = min(res, abs(leftSum - rightSum))
return res
</code></pre>

