kth-smallest-product-of-two-sorted-arrays.py<pre><code>class Solution:
def kthSmallestProduct(self, nums1: List[int], nums2: List[int], k: int) -&gt; int:
neg1, pos1 = [-x for x in nums1 if x &lt; 0][::-1], [x for x in nums1 if x &gt;= 0]
neg2, pos2 = [-x for x in nums2 if x &lt; 0][::-1], [x for x in nums2 if x &gt;= 0]
neg = len(neg1) * len(pos2) + len(neg2) * len(pos1)
if k &gt; neg:
k -= neg
s = 1
else:
k = neg - k + 1
neg2, pos2 = pos2, neg2
s = -1
def count(A, B, t):
res = 0
j = len(B) - 1
for x in A:
while j &gt;= 0 and x * B[j] &gt; t:
j -= 1
res += j + 1
return res
left, right = 0, 10 ** 10
while left &lt; right:
mid = left + (right - left) // 2
if count(neg1, neg2, mid) + count(pos1, pos2, mid) &gt;= k:
right = mid
else:
left = mid + 1
return left * s
