if 0 &lt;= dx &lt; rows and 0 &lt;= dy &lt; cols and grid[dx][dy] != 0 and (dx, dy) not in visited:
queue.append((dx, dy, distance + 1))
visited.add((dx, dy))
return [[-x, -y] for _, _, x, y in sorted(heap, reverse = 1)]
