escape-the-spreading-fire.py<pre><code>class Solution:
def maximumMinutes(self, grid: List[List[int]]) -&gt; int:
rows, cols = len(grid), len(grid[0])
INF = 10 ** 10
dist = [[INF] * cols for _ in range(rows)]
fire = deque()
for x in range(rows):
for y in range(cols):
if grid[x][y] == 1:
dist[x][y] = 0
fire.append((0, x, y))
while fire:
d, x, y = fire.popleft()
