count-unreachable-pairs-of-nodes-in-an-undirected-graph.py<pre><code>class DSU:
def __init__(self, n):
self.graph = list(range(n))
def find(self, x):
if self.graph[x] != x:
self.graph[x] = self.find(self.graph[x])
return self.graph[x]
def union(self, x, y):
ux, uy = self.find(x), self.find(y)
self.graph[ux] = uy
def connected(self, x, y):
return self.find(x) == self.find(y)
def disconnect(self, x):
self.graph[x] = x
class Solution:
def countPairs(self, n: int, edges: List[List[int]]) -&gt; int:
dsu = DSU(n)
for a, b in edges:
dsu.union(a, b)
parents = [0] * n
pp = [-1] * n
for node in range(n):
p = dsu.find(node)
pp[node] = p
parents[p] += 1
res = 0
for node in range(n):
res += n - parents[pp[node]]
return res // 2
</code></pre>

