longest-increasing-subsequence-ii.py<pre><code>class SegmentTree:
# https://github.com/cheran-senthil/PyRival/blob/master/pyrival/data_structures/SegmentTree.py
def __init__(self, data, default=0, func=max):
"""initialize the segment tree with data"""
self._default = default
self._func = func
self._len = len(data)
self._size = _size = 1 &lt;&lt; (self._len - 1).bit_length()
self.data = [default] * (2 * _size)
self.data[_size:_size + self._len] = data
for i in reversed(range(_size)):
self.data[i] = func(self.data[i + i], self.data[i + i + 1])
def __delitem__(self, idx):
self[idx] = self._default
def __getitem__(self, idx):
return self.data[idx + self._size]
def __setitem__(self, idx, value):
idx += self._size
self.data[idx] = value
idx &gt;&gt;= 1
while idx:
self.data[idx] = self._func(
self.data[2 * idx], self.data[2 * idx + 1])
idx &gt;&gt;= 1
def __len__(self):
return self._len
def query(self, start, stop):
"""func of data[start, stop)"""
start += self._size
stop += self._size
res_left = res_right = self._default
while start &lt; stop:
if start &amp; 1:
res_left = self._func(res_left, self.data[start])
start += 1
if stop &amp; 1:
stop -= 1
res_right = self._func(self.data[stop], res_right)
start &gt;&gt;= 1
stop &gt;&gt;= 1
return self._func(res_left, res_right)
def __repr__(self):
return "SegmentTree({0})".format(self.data)
class Solution:
def lengthOfLIS(self, nums: List[int], k: int) -&gt; int:
N = len(nums)
m = max(nums)
st = SegmentTree([0] * (m + 1))
res = 1
for x in nums:
left, right = max(1, x - k), x
q = st.query(left, right)
st[x] = 1 + q
if st[x] &gt; res:
res = st[x]
