cnt = [0] * 10
for i in range(N):
c = ord(words[i]) - ord("0")
if i &gt; 0:
for j in range(10):
for k in range(10):
dp[i][j][k] = dp[i - 1][j][k]
if k == c:
dp[i][j][k] += cnt[j]
cnt[c] += 1
return dp
prefix, suffix = build(s), build(s[::-1])[::-1]
for i in range(2, N - 2):
for j in range(10):
for k in range(10):
res += prefix[i - 1][j][k] * suffix[i + 1][j][k]
res %= M
return res
